package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.lang.reflect.Method;

class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void toJson_withNonNullObject_callsToJsonWithClass() throws Exception {
    // Arrange
    Object src = "test string";
    Appendable writer = mock(Appendable.class);

    // Use reflection to spy on private toJson(Object, Type, Appendable)
    Gson spyGson = spy(gson);

    // get the specific toJson(Object, Type, Appendable) method
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, java.lang.reflect.Type.class, Appendable.class);
    toJsonMethod.setAccessible(true);

    // doNothing on the specific method via doAnswer
    doAnswer(invocation -> null).when(spyGson).toJson(any(), any(), any());

    // Act
    spyGson.toJson(src, writer);

    // Assert
    verify(spyGson).toJson(src, src.getClass(), writer);
  }

  @Test
  void toJson_withNullObject_callsToJsonWithJsonNullInstance() throws Exception {
    // Arrange
    Appendable writer = mock(Appendable.class);

    // Spy on Gson to verify call to toJson(JsonNull.INSTANCE, Appendable)
    Gson spyGson = spy(gson);

    // Use reflection to access private static JsonNull.INSTANCE
    Class<?> jsonNullClass = Class.forName("com.google.gson.JsonNull");
    Object jsonNullInstance = jsonNullClass.getField("INSTANCE").get(null);

    // get the specific toJson(JsonElement, Appendable) method
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", com.google.gson.JsonElement.class, Appendable.class);
    toJsonMethod.setAccessible(true);

    // doNothing on the specific method via doAnswer
    doAnswer(invocation -> null).when(spyGson).toJson(any(com.google.gson.JsonElement.class), any(Appendable.class));

    // Act
    spyGson.toJson(null, writer);

    // Assert
    verify(spyGson).toJson((com.google.gson.JsonElement) jsonNullInstance, writer);
  }

  @Test
  void toJson_withNullObject_andWriterThrows_throwsJsonIOException() {
    // Arrange
    Appendable writer = mock(Appendable.class);
    try {
      doThrow(new IOException("append error")).when(writer).append(any(CharSequence.class));
    } catch (IOException e) {
      fail("Setup failed: " + e);
    }

    // Act & Assert
    JsonIOException thrown = assertThrows(JsonIOException.class, () -> gson.toJson(null, writer));
    assertEquals("append error", thrown.getCause().getMessage());
  }
}
